import React, { useEffect, useState, useRef } from "react";
import "./BloodBankPage.css";

const API_BASE = (process.env.REACT_APP_API_BASE || "http://localhost:5000/api").replace(/\/+$/, "");

const BloodBankPage = () => {
  const [search, setSearch] = useState("");
  const [showSuggestions, setShowSuggestions] = useState(false);
  const cardRefs = useRef({});
  const [centers, setCenters] = useState([
    { id: 1, name: "Apollo Blood Bank", location: "Hyderabad", available: true, bloodTypes: ["A+", "O+", "B+"] },
    { id: 2, name: "Red Cross Blood Center", location: "Vijayawada", available: false, bloodTypes: ["A-", "AB+"] },
    { id: 3, name: "Care Hospitals Blood Bank", location: "Visakhapatnam", available: true, bloodTypes: ["O-", "B+"] },
    { id: 4, name: "NIMS Blood Bank", location: "Guntur", available: false, bloodTypes: ["AB-", "B-"] },
    { id: 5, name: "Medico Blood Center", location: "Tirupati", available: true, bloodTypes: ["A+", "AB+", "O+"] },
  ]);

  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(`${API_BASE}/public/blood-centers`);
        const list = await res.json();
        if (Array.isArray(list) && list.length) {
          setCenters(list.map((c, idx) => ({
            id: c._id || `srv-${idx}`,
            name: c.name,
            location: c.location || "",
            available: Boolean(c.available),
            bloodTypes: Array.isArray(c.bloodTypes) ? c.bloodTypes : [],
          })));
        }
      } catch (_) {}
    })();
  }, []);

  const filteredCenters = centers.filter(
    (center) =>
      center.name.toLowerCase().includes(search.toLowerCase()) ||
      center.location.toLowerCase().includes(search.toLowerCase()) ||
      center.bloodTypes.some((type) => type.toLowerCase().includes(search.toLowerCase()))
  );

  const suggestions = centers
    .flatMap((center) =>
      center.bloodTypes.map((type) => ({
        label: `${center.name} (${type})`,
        center,
      }))
    )
    .filter(
      (item) =>
        item.label.toLowerCase().includes(search.toLowerCase()) ||
        item.center.location.toLowerCase().includes(search.toLowerCase())
    );

  const handleSuggestionClick = (suggestion) => {
    setSearch(suggestion.center.name);
    setShowSuggestions(false);
    if (cardRefs.current[suggestion.center.id]) {
      cardRefs.current[suggestion.center.id].scrollIntoView({ behavior: "smooth", block: "center" });
    }
  };

  return (
    <div className="bloodbank-container">
      <h2>Available Blood Banks</h2>

      <div className="search-section">
        <input
          type="text"
          placeholder="Search by blood type, name or location..."
          value={search}
          onChange={(e) => {
            setSearch(e.target.value);
            setShowSuggestions(true);
          }}
          onBlur={() => setTimeout(() => setShowSuggestions(false), 150)}
          className="modern-search-input"
        />
        <button className="modern-search-btn">Search</button>

        {showSuggestions && search && (
          <ul className="modern-suggestion-box suggestions-list">
            {suggestions.length > 0 ? (
              suggestions.map((item, idx) => (
                <li
                  key={idx}
                  className="modern-suggestion-item"
                  onClick={() => handleSuggestionClick(item)}
                >
                  <strong>{item.center.name}</strong>
                  <span className="suggestion-type">
                    ({item.center.location} • {item.center.bloodTypes.join(", ")})
                  </span>
                </li>
              ))
            ) : (
              <li className="modern-no-suggestion">No results found</li>
            )}
          </ul>
        )}
      </div>

      <div className="bloodbank-list">
        {filteredCenters.length > 0 ? (
          filteredCenters.map((center) => (
            <div
              key={center.id}
              ref={(el) => (cardRefs.current[center.id] = el)}
              className={`bloodbank-card ${center.available ? "available" : "not-available"}`}
            >
              <h3>{center.name}</h3>
              <p>{center.location}</p>
              <p>
                <strong>Blood Types:</strong> {center.bloodTypes.join(", ")}
              </p>
              <span className="status">
                {center.available ? "✅ Available" : "❌ Not Available"}
              </span>
            </div>
          ))
        ) : (
          <p className="no-results">No matching results found.</p>
        )}
      </div>
    </div>
  );
};

export default BloodBankPage;
